try:
    w3 = Web3(Web3.HTTPProvider(INFURA_URL))
    if not w3.is_connected():
        print("Warning: Could not connect to Ethereum provider. Signature verification will still work, but chain interactions will fail.")
        # Fallback to a Web3 instance without a provider if connection fails
        w3 = Web3()
except Exception as e:
    print(f"Error initializing Web3 with provider: {e}. Falling back to Web3 instance without a provider.")
    w3 = Web3()


@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    data = request.get_json()

    if not data:
        return jsonify({"error": "Invalid JSON payload"}), 400

    message = data.get('message')
    signature = data.get('signature')
    expected_address = data.get('address') # The address the user claims to be

    if not all([message, signature, expected_address]):
        return jsonify({"error": "Missing 'message', 'signature', or 'address' in request"}), 400

    try:
        # 1. Encode the message
        # web3.py's `recover_message` expects the message to be encoded as per EIP-191
        # The `encode_defunct` function handles this.
        encoded_message = encode_defunct(text=message)

        # 2. Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )

        # 3. Compare the recovered address with the expected address
        # Ensure case-insensitive comparison for Ethereum addresses
        is_valid = (recovered_address.lower() == expected_address.lower())

        if is_valid:
            return jsonify({
                "status": "success",
                "message": "Signature verified successfully.",
                "recovered_address": recovered_address,
                "is_authenticated": True
            }), 200
        else:
            return jsonify({
                "status": "failure",
                "message": "Signature verification failed. Recovered address does not match expected address.",
                "recovered_address": recovered_address,
                "expected_address": expected_address,
                "is_authenticated": False
            }), 401

    except ValueError as e:
        return jsonify({"error": f"Invalid signature or message format: {e}"}), 400
    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500

